from collections import deque


class _N:
    __slots__ = ("val", "left", "right")
    def __init__(self, v): self.val = v; self.left = None; self.right = None


def _build(vals):
    if not vals or vals[0] is None: return None
    root = _N(vals[0]); q = deque([root]); i = 1
    while q and i < len(vals):
        n = q.popleft()
        if i < len(vals):
            if vals[i] is not None: n.left = _N(vals[i]); q.append(n.left)
            i += 1
        if i < len(vals):
            if vals[i] is not None: n.right = _N(vals[i]); q.append(n.right)
            i += 1
    return root


def is_valid_bst(root):
    r = _build(root)

    def valid(node, lo, hi):
        if node is None:
            return True
        if not (lo < node.val < hi):
            return False
        return valid(node.left, lo, node.val) and valid(node.right, node.val, hi)

    return valid(r, float('-inf'), float('inf'))
